#!/usr/bin/env bash
# case-interview.sh — Case interview（招聘 / 入行） SOP walkthrough for 管理咨询.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="管理咨询"
WORKFLOW="Case interview（招聘 / 入行）"

usage() {
  cat <<EOF
case-interview.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./case-interview.sh             # interactive
  ./case-interview.sh --dry-run
  ./case-interview.sh --json
  ./case-interview.sh --explain
  ./case-interview.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Case interview（招聘 / 入行）" 工作流。

一句话: 进咨询的「守门流程」—— 面试官给一个商业问题，候选人当场「复述+澄清 → 搭 MECE 结构 → 分析 → market sizing → recommendation」，考的就是 workflow 2（假设驱动问题解决）+ workflow 3（结论先行沟通）的现场压缩版；外加 fit/PEI 行为面。

入门 SOP 共 6 步, 失败模式自检 6 项。

相关心智模型:
  • 假设驱动是地图不是答案：先射箭再画靶 ⇄ 随时 kill 假设（第一性张力）: 面对模糊大问题，资深咨询人不从穷举数据出发，而是 Day-1 就基于经验立一个**可证伪**的初步答案（hypothesis / initial hypothesis）当地图，再只做能 kill 或 
  • 战略 = 做选择 / 做不同，不是运营效率、不是愿望清单: 这行顶级战略 figure 跨流派一致——战略的本质是**逼自己做取舍**（Martin：where-to-play × how-to-win 两个不可分割的选择；Rumelt：kernel = 诊断

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**听题 + 复述 + 澄清**：拿到 case prompt，复述确认理解，问 2-3 个澄清问题（目标是什么？范围？成功标准？）。(evidence: [T03-S003])"
  "**搭结构（MECE issue tree）**：花 30-60 秒在纸上搭一个 MECE 的拆解结构（资深做法是 hypothesis-driven 而非死套框架）；讲给面试官听，对齐路径。(evidence: [T03-S002, T06-S007])"
  "**分析（按结构推进）**：沿结构逐支分析，要数据就向面试官要，边算边说思路；遇定量分支做计算。(evidence: [T03-S003])"
  "**Market sizing（估算题，常嵌入）**：用结构化假设（人口 × 渗透率 × 单价 / 自上而下或自下而上）+ 心算估算市场规模，讲清每个假设。(evidence: [T03-S003, T06-S008])"
  "**Recommendation（结论先行）**：最后用金字塔结构给一句话建议 + 2-3 个支撑理由 + 风险/next step；结论先行，不复述分析过程。(evidence: [T04-S001, T03-S003])"
  "**Fit / PEI（行为面）**：与 case 权重相当 —— McKinsey PEI 对**单个 story 深挖 10-25 个追问**，考 Connection/Drive/Leadership/Growth；很多人栽在 PEI 而非 case。(evidence: [T03-S004, T06-S008])"
)
declare -a FAILURE_MODES=(
  "**不澄清就开答**：理解错题目方向。避免：复述 + 问 2-3 个澄清问题再动手。**自检**：「我确认过目标、范围、成功标准了吗？」"
  "**死套框架（frameworks-as-theater）**：机械套五力/3C 不管贴不贴题。避免：针对这道题 hypothesis-driven 搭定制结构。**自检**：「这个结构是为这道题搭的，还是我背的现成框架硬套？」"
  "**结构不 MECE**：拆桶重叠/漏项。避免：拆完检查不重不漏。**自检**：「我这几个桶有重叠吗？合起来穷尽吗？」"
  "**market sizing 乱拍数**：不拆结构、假设没逻辑。避免：人口 × 渗透率 × 单价式拆解，每个假设讲清理由。**自检**：「我每个估算假设，都说得出为什么取这个数吗？」"
  "**不给 so-what / 结论埋最后**：复述分析、不提炼建议。避免：结论先行的 recommendation + 阶段小结。**自检**：「面试官只听我最后 30 秒，能拿到我的建议吗？」"
  "**裸面 PEI**：只练 case 忽略行为面。避免：打磨 2-3 个能扛深挖的 story。**自检**：「我的 story 能扛住 15 个『然后呢/你具体做了什么』的追问吗？」(evidence: [T03-S004])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "case-interview-walkthrough"
fi
